+
+const SUPPORTED_TASKS = [
+  "validate-user-definition",
+  "validate-user-sentence",
+] as const;
+
+type SupportedTask = (typeof SUPPORTED_TASKS)[number];
+
+const feedbackSchema = z.object({
+  correct: z.boolean(),
+  exampleSentence: z.string(),
+  aiResponse: z.string(),
+  hint: z.string(),
+});
+
+function isRecord(value: unknown): value is Record<string, unknown> {
+  return typeof value === "object" && value !== null;
+}
+
+function getString(value: unknown): string {
+  return typeof value === "string" ? value.trim() : "";
+}
+
+function badRequest(message: string) {
+  return NextResponse.json({ success: false, message }, { status: 400 });
+}
+
+function validateTask(task: unknown): SupportedTask | null {
+  if (typeof task !== "string") return null;
+  return SUPPORTED_TASKS.includes(task as SupportedTask)
+    ? (task as SupportedTask)
+    : null;
+}
+
+async function generateFeedback(prompt: string) {
+  const apiKey = process.env.OPENROUTER_KEY;
+
+  if (!apiKey) {
+    throw new Error("OPENROUTER_KEY is not configured");
+  }
+
+  const openrouter = createOpenRouter({ apiKey });
+
+  const { object } = await generateObject({
+    model: openrouter(process.env.OPENROUTER_MODEL || "openai/gpt-4o-mini"),
+    schema: feedbackSchema,
+    mode: "json",
+    temperature: 0.2,
+    prompt,
+  });
+
+  return object;
+}
