"use client";

import React, { useEffect, useMemo, useReducer } from "react";
import { useLocalStorage } from "@/lib/useLocalStorage";
import {
  ChatAPI_FailureResponse,
  ChatAPI_WriteASentence_SuccessResponse,
  PracticePerformanceData,
  QuizAttempt,
  VocabsData,
  VocabularyWord,
  WordPerformance,
  vocabs_database,
} from "@/types/vocabulary";
import { Button } from "@/components/ui/button";
import { AnimatePresence, motion } from "framer-motion";
import {
  ArrowLeft,
  ArrowRight,
  BotIcon,
  CheckCircle,
  ChevronDown,
  ChevronUp,
  RotateCcw,
  X,
  XCircle,
} from "lucide-react";
import { playSound } from "@/lib/playSound";
import Link from "next/link";

interface SentenceQuestion {
  word: VocabularyWord;
}

interface VocabsFormASentencePracticeProps {
  onBackToPracticeSelection?: () => void;
}

interface SentenceState {
  currentQuestionIndex: number;
  userSentence: string;
  showResult: boolean;
  score: number;
  answeredQuestions: boolean[];
  userAnswers: string[];
  isComplete: boolean;
  showUserSentences: { [key: number]: boolean };
  questionStartTime: number;
  restartKey: number;
  isSubmitting: boolean;
  feedbackByQuestion: { [key: number]: string };
  hintsByQuestion: { [key: number]: string };
  examplesByQuestion: { [key: number]: string };
  aiResults: { [key: number]: boolean };
}

type SentenceAction =
  | { type: "INITIALIZE_SENTENCES"; payload: { questionCount: number } }
  | { type: "UPDATE_SENTENCE"; payload: string }
  | { type: "START_SUBMISSION" }
  | {
      type: "SUBMIT_SENTENCE";
      payload: {
        isCorrect: boolean;
        aiResponse: string;
        hint: string;
        exampleSentence: string;
      };
    }
  | { type: "NEXT_QUESTION" }
  | { type: "PREVIOUS_QUESTION" }
  | { type: "FINISH_PRACTICE" }
  | { type: "RESTART_PRACTICE"; payload: { questionCount: number } }
  | { type: "TOGGLE_USER_SENTENCES"; payload: number }
  | { type: "SET_QUESTION_START_TIME"; payload: number }
  | {
      type: "LOAD_QUESTION_STATE";
      payload: { userSentence: string; showResult: boolean };
    };

function sentenceReducer(
  state: SentenceState,
  action: SentenceAction
): SentenceState {
  switch (action.type) {
    case "INITIALIZE_SENTENCES":
      return {
        ...state,
        answeredQuestions: new Array(action.payload.questionCount).fill(false),
        userAnswers: new Array(action.payload.questionCount).fill(""),
        questionStartTime: Date.now(),
        feedbackByQuestion: {},
        hintsByQuestion: {},
        examplesByQuestion: {},
        aiResults: {},
      };

    case "UPDATE_SENTENCE":
      return {
        ...state,
        userSentence: action.payload,
      };

    case "START_SUBMISSION":
      return {
        ...state,
        isSubmitting: true,
      };

    case "SUBMIT_SENTENCE": {
      const newAnsweredQuestions = [...state.answeredQuestions];
      const newUserAnswers = [...state.userAnswers];
      const newFeedbackByQuestion = { ...state.feedbackByQuestion };
      const newHintsByQuestion = { ...state.hintsByQuestion };
      const newExamplesByQuestion = { ...state.examplesByQuestion };
      const newAiResults = { ...state.aiResults };

      newAnsweredQuestions[state.currentQuestionIndex] = true;
      newUserAnswers[state.currentQuestionIndex] = state.userSentence.trim();
      newFeedbackByQuestion[state.currentQuestionIndex] =
        action.payload.aiResponse;
      newHintsByQuestion[state.currentQuestionIndex] = action.payload.hint;
      newExamplesByQuestion[state.currentQuestionIndex] =
        action.payload.exampleSentence;
      newAiResults[state.currentQuestionIndex] = action.payload.isCorrect;

      return {
        ...state,
        showResult: true,
        isSubmitting: false,
        score:
          !state.answeredQuestions[state.currentQuestionIndex] &&
          action.payload.isCorrect
            ? state.score + 1
            : state.score,
        answeredQuestions: newAnsweredQuestions,
        userAnswers: newUserAnswers,
        feedbackByQuestion: newFeedbackByQuestion,
        hintsByQuestion: newHintsByQuestion,
        examplesByQuestion: newExamplesByQuestion,
        aiResults: newAiResults,
      };
    }

    case "NEXT_QUESTION":
      if (state.currentQuestionIndex + 1 >= state.answeredQuestions.length) {
        return {
          ...state,
          isComplete: true,
        };
      }

      return {
        ...state,
        currentQuestionIndex: state.currentQuestionIndex + 1,
        questionStartTime: Date.now(),
      };

    case "PREVIOUS_QUESTION":
      if (state.currentQuestionIndex === 0) return state;

      return {
        ...state,
        currentQuestionIndex: state.currentQuestionIndex - 1,
        questionStartTime: Date.now(),
      };

    case "FINISH_PRACTICE":
      return {
        ...state,
        isComplete: true,
      };

    case "RESTART_PRACTICE":
      return {
        currentQuestionIndex: 0,
        userSentence: "",
        showResult: false,
        score: 0,
        answeredQuestions: new Array(action.payload.questionCount).fill(false),
        userAnswers: new Array(action.payload.questionCount).fill(""),
        isComplete: false,
        showUserSentences: {},
        questionStartTime: Date.now(),
        restartKey: Date.now(),
        isSubmitting: false,
        feedbackByQuestion: {},
        hintsByQuestion: {},
        examplesByQuestion: {},
        aiResults: {},
      };

    case "TOGGLE_USER_SENTENCES":
      return {
        ...state,
        showUserSentences: {
          ...state.showUserSentences,
          [action.payload]: !state.showUserSentences[action.payload],
        },
      };

    case "SET_QUESTION_START_TIME":
      return {
        ...state,
        questionStartTime: action.payload,
      };

    case "LOAD_QUESTION_STATE":
      return {
        ...state,
        userSentence: action.payload.userSentence,
        showResult: action.payload.showResult,
        isSubmitting: false,
      };

    default:
      return state;
  }
}

const initialSentenceState: SentenceState = {
  currentQuestionIndex: 0,
  userSentence: "",
  showResult: false,
  score: 0,
  answeredQuestions: [],
  userAnswers: [],
  isComplete: false,
  showUserSentences: {},
  questionStartTime: Date.now(),
  restartKey: 0,
  isSubmitting: false,
  feedbackByQuestion: {},
  hintsByQuestion: {},
  examplesByQuestion: {},
  aiResults: {},
};

function calculateMasteryLevel(
  correctAttempts: number,
  totalAttempts: number,
  consecutiveCorrect: number
): WordPerformance["masteryLevel"] {
  if (totalAttempts === 0) return "learning";

  const accuracy = correctAttempts / totalAttempts;

  if (accuracy >= 0.9 && consecutiveCorrect >= 3) return "mastered";
  if (accuracy >= 0.7 && consecutiveCorrect >= 2) return "proficient";
  if (accuracy >= 0.5) return "learning";
  return "struggling";
}

function escapeRegExp(value: string) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function evaluateSentenceLocally(
  sentence: string,
  word: string,
  exampleSentence: string
) {
  const trimmedSentence = sentence.trim();
  const wordPattern = new RegExp(
    `\\b${escapeRegExp(word)}(?:s|es|ed|ing|ly)?\\b`,
    "i"
  );
  const containsWord = wordPattern.test(trimmedSentence);
  const words = trimmedSentence.match(/[A-Za-z']+/g) || [];
  const isLongEnough = words.length >= 4;
  const hasVerbLikeWord =
    /\b(is|are|was|were|be|being|been|am|has|have|had|do|does|did|can|could|will|would|should|may|might|must)\b/i.test(
      trimmedSentence
    ) || words.some((token) => /(ed|ing|s)$/i.test(token) && token.length > 3);
  const isCorrect = containsWord && isLongEnough && hasVerbLikeWord;

  return {
    correct: isCorrect,
    exampleSentence:
      exampleSentence || `Try writing a clear sentence with "${word}".`,
    aiResponse: isCorrect
      ? "Basic check passed: your sentence includes the vocabulary word and reads like a complete thought."
      : "AI feedback is unavailable, so a basic check was used. Make sure your sentence includes the vocabulary word and expresses a complete thought.",
    hint: containsWord
      ? "Try adding more context so the word's meaning is clear."
      : `Your sentence must include "${word}" or a close form of it.`,
  };
}

function prioritizeWords(
  learnedWords: VocabularyWord[],
  practicePerformance: PracticePerformanceData
) {
  const categorizedWords = {
    notPracticed: [] as VocabularyWord[],
    struggling: [] as VocabularyWord[],
    learning: [] as VocabularyWord[],
    proficient: [] as VocabularyWord[],
    mastered: [] as VocabularyWord[],
  };

  learnedWords.forEach((word) => {
    const performance = practicePerformance.wordPerformance[word.word];

    if (!performance) {
      categorizedWords.notPracticed.push(word);
      return;
    }

    switch (performance.masteryLevel) {
      case "struggling":
        categorizedWords.struggling.push(word);
        break;
      case "learning":
        categorizedWords.learning.push(word);
        break;
      case "proficient":
        categorizedWords.proficient.push(word);
        break;
      case "mastered":
        categorizedWords.mastered.push(word);
        break;
      default:
        categorizedWords.notPracticed.push(word);
    }
  });

  Object.keys(categorizedWords).forEach((key) => {
    categorizedWords[key as keyof typeof categorizedWords].sort(
      () => Math.random() - 0.5
    );
  });

  return [
    ...categorizedWords.notPracticed,
    ...categorizedWords.struggling,
    ...categorizedWords.learning,
    ...categorizedWords.proficient,
    ...categorizedWords.mastered,
  ];
}

export default function VocabsFormaSentencePractice({
  onBackToPracticeSelection,
}: VocabsFormASentencePracticeProps = {}) {
  const [sentenceState, dispatch] = useReducer(
    sentenceReducer,
    initialSentenceState
  );

  const [vocabsData, setVocabsData] = useLocalStorage<VocabsData>(
    "vocabsData",
    {
      learntVocabs: [],
      userSentences: {},
    }
  );

  const [practicePerformance, setPracticePerformance] =
    useLocalStorage<PracticePerformanceData>("practicePerformanceData", {
      attempts: [],
      wordPerformance: {},
      lastUpdated: Date.now(),
      totalQuizzesTaken: 0,
      overallAccuracy: 0,
      strongWords: [],
      weakWords: [],
      improvingWords: [],
    });

  const learnedWords = useMemo(() => {
    return vocabs_database.filter((word) =>
      vocabsData.learntVocabs.includes(word.word)
    );
  }, [vocabsData.learntVocabs]);

  const sentenceQuestions = useMemo<SentenceQuestion[]>(() => {
    if (learnedWords.length === 0) return [];

    return prioritizeWords(learnedWords, practicePerformance).map((word) => ({
      word,
    }));
  }, [
    learnedWords,
    practicePerformance,
    sentenceState.restartKey,
  ]);

  useEffect(() => {
    dispatch({
      type: "INITIALIZE_SENTENCES",
      payload: { questionCount: sentenceQuestions.length },
    });
  }, [sentenceQuestions.length]);

  useEffect(() => {
    if (sentenceState.userAnswers[sentenceState.currentQuestionIndex]) {
      dispatch({
        type: "LOAD_QUESTION_STATE",
        payload: {
          userSentence:
            sentenceState.userAnswers[sentenceState.currentQuestionIndex],
          showResult:
            sentenceState.answeredQuestions[
              sentenceState.currentQuestionIndex
            ],
        },
      });
    } else {
      dispatch({
        type: "LOAD_QUESTION_STATE",
        payload: {
          userSentence: "",
          showResult: false,
        },
      });
    }
  }, [
    sentenceState.currentQuestionIndex,
    sentenceState.userAnswers,
    sentenceState.answeredQuestions,
  ]);

  useEffect(() => {
    dispatch({ type: "SET_QUESTION_START_TIME", payload: Date.now() });
  }, [sentenceState.currentQuestionIndex]);

  const currentQuestion = sentenceQuestions[sentenceState.currentQuestionIndex];

  const saveCorrectSentence = (word: string, sentence: string) => {
    setVocabsData((prevData) => {
      const existingSentences = prevData.userSentences[word] || [];

      if (
        existingSentences.some(
          (existingSentence) =>
            existingSentence.trim().toLowerCase() ===
            sentence.trim().toLowerCase()
        )
      ) {
        return prevData;
      }

      return {
        ...prevData,
        userSentences: {
          ...prevData.userSentences,
          [word]: [...existingSentences, sentence.trim()],
        },
      };
    });
  };

  const updateWordPerformance = (
    word: string,
    isCorrect: boolean,
    timeSpent: number,
    userSentence: string
  ) => {
    setPracticePerformance((prevData) => {
      const updatedData = { ...prevData };

      const wordPerf = updatedData.wordPerformance[word] || {
        word,
        totalAttempts: 0,
        correctAttempts: 0,
        incorrectAttempts: 0,
        lastAttemptTimestamp: Date.now(),
        averageTimeSpent: 0,
        strugglingAreas: [],
        masteryLevel: "learning" as const,
        consecutiveCorrect: 0,
        consecutiveIncorrect: 0,
      };

      wordPerf.totalAttempts++;
      wordPerf.lastAttemptTimestamp = Date.now();

      if (isCorrect) {
        wordPerf.correctAttempts++;
        wordPerf.consecutiveCorrect++;
        wordPerf.consecutiveIncorrect = 0;
      } else {
        wordPerf.incorrectAttempts++;
        wordPerf.consecutiveIncorrect++;
        wordPerf.consecutiveCorrect = 0;

        if (!wordPerf.strugglingAreas.includes("sentence")) {
          wordPerf.strugglingAreas.push("sentence");
        }
      }

      const totalTime =
        wordPerf.averageTimeSpent * (wordPerf.totalAttempts - 1) + timeSpent;
      wordPerf.averageTimeSpent = totalTime / wordPerf.totalAttempts;
      wordPerf.masteryLevel = calculateMasteryLevel(
        wordPerf.correctAttempts,
        wordPerf.totalAttempts,
        wordPerf.consecutiveCorrect
      );

      updatedData.wordPerformance[word] = wordPerf;

      const attempt: QuizAttempt = {
        word,
        questionType: "sentence",
        isCorrect,
        userAnswer: userSentence,
        correctAnswer: currentQuestion.word.example,
        timeSpent,
        timestamp: Date.now(),
        difficulty: currentQuestion.word.difficulty,
      };

      updatedData.attempts.push(attempt);
      updatedData.lastUpdated = Date.now();

      const totalCorrect = updatedData.attempts.filter(
        (attemptData) => attemptData.isCorrect
      ).length;
      updatedData.overallAccuracy = totalCorrect / updatedData.attempts.length;

      const allWords = Object.values(updatedData.wordPerformance);
      updatedData.strongWords = allWords
        .filter(
          (wordData) =>
            wordData.masteryLevel === "mastered" ||
            wordData.masteryLevel === "proficient"
        )
        .map((wordData) => wordData.word);
      updatedData.weakWords = allWords
        .filter((wordData) => wordData.masteryLevel === "struggling")
        .map((wordData) => wordData.word);
      updatedData.improvingWords = allWords
        .filter(
          (wordData) =>
            wordData.masteryLevel === "learning" &&
            wordData.consecutiveCorrect > 0
        )
        .map((wordData) => wordData.word);

      return updatedData;
    });
  };

  const handleSubmitSentence = async () => {
    const userSentence = sentenceState.userSentence.trim();
    if (!userSentence || !currentQuestion) return;

    playSound("button-pressed.wav");
    dispatch({ type: "START_SUBMISSION" });

    let result = evaluateSentenceLocally(
      userSentence,
      currentQuestion.word.word,
      currentQuestion.word.example
    );

    try {
      const response = await fetch("/api/chat", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          message: userSentence,
          data: {
            word: currentQuestion.word.word,
            userSentence,
            correctDefinition: currentQuestion.word.definition,
            exampleSentence: currentQuestion.word.example,
          },
          task: "validate-user-sentence",
        }),
      });

      const responseData:
        | ChatAPI_WriteASentence_SuccessResponse
        | ChatAPI_FailureResponse = await response.json();

      if (response.ok && responseData.success) {
        result = responseData.result;
      }
    } catch (error) {
      console.error("Sentence feedback error:", error);
    }

    const timeSpent = Math.round(
      (Date.now() - sentenceState.questionStartTime) / 1000
    );

    dispatch({
      type: "SUBMIT_SENTENCE",
      payload: {
        isCorrect: result.correct,
        aiResponse: result.aiResponse,
        hint: result.hint,
        exampleSentence: result.exampleSentence,
      },
    });

    if (!sentenceState.answeredQuestions[sentenceState.currentQuestionIndex]) {
      updateWordPerformance(
        currentQuestion.word.word,
        result.correct,
        timeSpent,
        userSentence
      );

      if (result.correct) {
        saveCorrectSentence(currentQuestion.word.word, userSentence);
      }
    }

    if (result.correct) {
      playSound("correct-answer.wav");
