const SUPPORTED_TASKS = [
  "validate-user-definition",
  "validate-user-sentence",
] as const;

type SupportedTask = (typeof SUPPORTED_TASKS)[number];

const feedbackSchema = z.object({
  correct: z.boolean(),
  exampleSentence: z.string(),
  aiResponse: z.string(),
  hint: z.string(),
});

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function getString(value: unknown): string {
  return typeof value === "string" ? value.trim() : "";
}

function badRequest(message: string) {
  return NextResponse.json({ success: false, message }, { status: 400 });
}

function validateTask(task: unknown): SupportedTask | null {
  if (typeof task !== "string") return null;
  return SUPPORTED_TASKS.includes(task as SupportedTask)
    ? (task as SupportedTask)
    : null;
}

async function generateFeedback(prompt: string) {
  const apiKey = process.env.OPENROUTER_KEY;

  if (!apiKey) {
    throw new Error("OPENROUTER_KEY is not configured");
  }

  const openrouter = createOpenRouter({ apiKey });

  const { object } = await generateObject({
    model: openrouter(process.env.OPENROUTER_MODEL || "openai/gpt-4o-mini"),
    schema: feedbackSchema,
    mode: "json",
    temperature: 0.2,
    prompt,
  });

  return object;
}

function buildDefinitionPrompt(input: {
  word: string;
  userDefinition: string;
  correctDefinition: string;
  exampleSentence: string;
}) {
  return `You are a concise SAT vocabulary tutor.

Evaluate whether the learner's definition captures the meaning of the vocabulary word.
Be lenient about wording, but mark it incorrect if it misses the core meaning or describes another word.

Return structured JSON with:
- correct: whether the learner's definition is acceptable
- exampleSentence: a clear sentence using the vocabulary word
- aiResponse: one or two sentences of tutor-style feedback
- hint: a short hint if incorrect, or a short reinforcement if correct

Word: ${input.word}
Correct definition: ${input.correctDefinition}
Reference example: ${input.exampleSentence || "No reference example provided."}
Learner definition: ${input.userDefinition}`;
}

function buildSentencePrompt(input: {
  word: string;
  userSentence: string;
  correctDefinition: string;
  exampleSentence: string;
}) {
  return `You are a concise SAT vocabulary tutor.

Evaluate whether the learner's sentence uses the vocabulary word naturally and with the intended meaning.
The sentence must include the vocabulary word or a clear inflected form of it, be a complete thought, and fit the definition.
Do not require advanced grammar, but mark it incorrect if the word is absent, used with the wrong meaning, or the text is only a fragment.

Return structured JSON with:
- correct: whether the sentence is acceptable
- exampleSentence: a corrected or model sentence using the vocabulary word
- aiResponse: one or two sentences of tutor-style feedback
- hint: a short hint if incorrect, or a short reinforcement if correct

Word: ${input.word}
Definition: ${input.correctDefinition}
Reference example: ${input.exampleSentence || "No reference example provided."}
Learner sentence: ${input.userSentence}`;
}

export async function POST(request: NextRequest) {
  let body: unknown;

  try {
    body = await request.json();
  } catch {
    return badRequest("Request body must be valid JSON.");
  }

  if (!isRecord(body)) {
    return badRequest("Request body must be a JSON object.");
  }

  const task = validateTask(body.task);

  if (!task) {
    return badRequest(
      `Missing or unsupported task. Supported tasks: ${SUPPORTED_TASKS.join(
        ", "
      )}.`
    );
  }

  const data = isRecord(body.data) ? body.data : {};
  const message = getString(body.message);
  const word = getString(data.word);
  const correctDefinition = getString(data.correctDefinition);
  const exampleSentence = getString(data.exampleSentence);

  if (!word) {
    return badRequest("Missing required data.word.");
  }

  if (!correctDefinition) {
    return badRequest("Missing required data.correctDefinition.");
  }

  try {
    if (task === "validate-user-definition") {
      const userDefinition = getString(data.userDefinition) || message;

      if (!userDefinition) {
        return badRequest("Missing user definition.");
      }

      const result = await generateFeedback(
        buildDefinitionPrompt({
          word,
          userDefinition,
          correctDefinition,
          exampleSentence,
        })
      );

      return NextResponse.json({ success: true, result });
    }

    const userSentence = getString(data.userSentence) || message;

    if (!userSentence) {
      return badRequest("Missing user sentence.");
    }

    const result = await generateFeedback(
      buildSentencePrompt({
        word,
        userSentence,
        correctDefinition,
        exampleSentence,
      })
    );

    return NextResponse.json({ success: true, result });
  } catch (error) {
    console.error("Chat feedback error:", error);

    return NextResponse.json(
      {
        success: false,
        message: "Unable to generate vocabulary feedback right now.",
      },
      { status: 500 }
    );
  }
}

