"use client";

import * as React from "react";
import { Check, ChevronDown } from "lucide-react";
import { cn } from "@/lib/utils";

export interface Workspace {
  id: string;
  name: string;
  description?: string;
}

interface WorkspacesContextValue {
  workspaces: Workspace[];
  selectedWorkspace?: Workspace;
  isOpen: boolean;
  setIsOpen: React.Dispatch<React.SetStateAction<boolean>>;
  onWorkspaceChange: (workspace: Workspace) => void;
}

const WorkspacesContext = React.createContext<WorkspacesContextValue | null>(
  null
);

function useWorkspaces() {
  const context = React.useContext(WorkspacesContext);

  if (!context) {
    throw new Error("Workspace components must be used within Workspaces.");
  }

  return context;
}

interface WorkspacesProps<TWorkspace extends Workspace> {
  workspaces: TWorkspace[];
  selectedWorkspaceId?: string;
  onWorkspaceChange?: (workspace: TWorkspace) => void;
  children: React.ReactNode;
  className?: string;
}

function Workspaces<TWorkspace extends Workspace>({
  workspaces,
  selectedWorkspaceId,
  onWorkspaceChange,
  children,
  className,
}: WorkspacesProps<TWorkspace>) {
  const [isOpen, setIsOpen] = React.useState(false);
  const selectedWorkspace =
    workspaces.find((workspace) => workspace.id === selectedWorkspaceId) ||
    workspaces[0];

  return (
    <WorkspacesContext.Provider
      value={{
        workspaces,
        selectedWorkspace,
        isOpen,
        setIsOpen,
        onWorkspaceChange: (workspace) => {
          onWorkspaceChange?.(workspace as TWorkspace);
          setIsOpen(false);
        },
      }}
    >
      <div className={cn("relative", className)}>{children}</div>
    </WorkspacesContext.Provider>
  );
}

function WorkspaceTrigger({
  className,
}: React.ButtonHTMLAttributes<HTMLButtonElement>) {
  const { selectedWorkspace, isOpen, setIsOpen } = useWorkspaces();

  return (
    <button
      type="button"
      className={cn(
        "flex h-10 w-full items-center justify-between gap-3 rounded-lg border border-border bg-background px-3 py-2 text-sm shadow-sm transition-colors hover:bg-accent hover:text-accent-foreground",
        className
      )}
      onClick={() => setIsOpen((value) => !value)}
      aria-expanded={isOpen}
    >
      <span className="truncate font-medium">
        {selectedWorkspace?.name || "Select workspace"}
      </span>
      <ChevronDown
        className={cn("size-4 opacity-60 transition-transform", {
          "rotate-180": isOpen,
        })}
      />
    </button>
  );
}

function WorkspaceContent({
  title,
  className,
}: {
  title?: string;
  className?: string;
}) {
  const {
    workspaces,
    selectedWorkspace,
    isOpen,
    onWorkspaceChange,
  } = useWorkspaces();

  if (!isOpen) return null;

  return (
    <div
      className={cn(
        "absolute right-0 z-50 mt-2 w-full min-w-72 rounded-lg border border-border bg-background p-2 shadow-lg",
        className
      )}
    >
      {title && (
        <div className="px-3 py-2 text-xs font-semibold text-muted-foreground">
          {title}
        </div>
      )}
      <div className="space-y-1">
        {workspaces.map((workspace) => (
          <button
            key={workspace.id}
            type="button"
            className="flex w-full items-center justify-between gap-3 rounded-md px-3 py-2 text-left text-sm hover:bg-accent hover:text-accent-foreground"
            onClick={() => onWorkspaceChange(workspace)}
          >
            <span className="truncate">{workspace.name}</span>
            {selectedWorkspace?.id === workspace.id && (
              <Check className="size-4 text-blue-600" />
            )}
          </button>
        ))}
      </div>
    </div>
  );
}

export { Workspaces, WorkspaceTrigger, WorkspaceContent };

