        .slice(state.displayedQuestionsCount, nextCount)
        .map((q) => ({
          ...q,
          isLoading: true,
          hasError: false,
        }));

      return {
        ...state,
        questionsWithData: [...state.questionsWithData, ...newQuestions],
        displayedQuestionsCount: nextCount,
