  if (!statistics[assessment]) {
    statistics[assessment] = {
      answeredQuestions: [],
      answeredQuestionsDetailed: [],
      statistics: {},
    };
  }

  const assessmentStats = statistics[assessment];

  // Check if this question is already in the detailed list
