import type { UserProfileWithHistory } from "@/types/userProfile";

const USER_PROFILE_KEY = "userProfile";

const defaultProfile: UserProfileWithHistory = {
  totalXP: 0,
  level: 1,
  questionsAnswered: 0,
  correctAnswers: 0,
  incorrectAnswers: 0,
  answeredQuestionIds: [],
  xpHistory: [],
};

function calculateLevel(totalXP: number) {
  return Math.max(1, Math.floor(totalXP / 1000) + 1);
}

export function getUserProfile(): UserProfileWithHistory {
  if (typeof window === "undefined") return defaultProfile;

  try {
    const storedProfile = window.localStorage.getItem(USER_PROFILE_KEY);
    return storedProfile
      ? { ...defaultProfile, ...JSON.parse(storedProfile) }
      : defaultProfile;
  } catch {
    return defaultProfile;
  }
}

export function saveUserProfile(profile: UserProfileWithHistory) {
  if (typeof window === "undefined") return profile;

  window.localStorage.setItem(USER_PROFILE_KEY, JSON.stringify(profile));
  return profile;
}

export function addXPForCorrectAnswer(questionId: string, scoreBand = 1) {
  const profile = getUserProfile();
  const xpChange = Math.max(1, scoreBand) * 10;
  const nextProfile: UserProfileWithHistory = {
    ...profile,
    totalXP: profile.totalXP + xpChange,
    questionsAnswered: profile.answeredQuestionIds.includes(questionId)
      ? profile.questionsAnswered
      : profile.questionsAnswered + 1,
    correctAnswers: profile.correctAnswers + 1,
    answeredQuestionIds: profile.answeredQuestionIds.includes(questionId)
      ? profile.answeredQuestionIds
      : [...profile.answeredQuestionIds, questionId],
    xpHistory: [
      ...profile.xpHistory,
      { questionId, xpChange, timestamp: new Date().toISOString() },
    ],
  };

  nextProfile.level = calculateLevel(nextProfile.totalXP);
  return saveUserProfile(nextProfile);
}

export function reduceXPForIncorrectAnswer(questionId: string, scoreBand = 1) {
  const profile = getUserProfile();
  const xpChange = -Math.floor((Math.max(1, scoreBand) * 10) / 2);
  const nextTotalXP = Math.max(0, profile.totalXP + xpChange);
  const nextProfile: UserProfileWithHistory = {
    ...profile,
    totalXP: nextTotalXP,
    questionsAnswered: profile.answeredQuestionIds.includes(questionId)
      ? profile.questionsAnswered
      : profile.questionsAnswered + 1,
    incorrectAnswers: profile.incorrectAnswers + 1,
    answeredQuestionIds: profile.answeredQuestionIds.includes(questionId)
      ? profile.answeredQuestionIds
      : [...profile.answeredQuestionIds, questionId],
    xpHistory: [
      ...profile.xpHistory,
      { questionId, xpChange, timestamp: new Date().toISOString() },
    ],
  };

  nextProfile.level = calculateLevel(nextProfile.totalXP);
  return saveUserProfile(nextProfile);
}

