export function MultiSelectCombobox<T extends string>({
  label,
  options = [],
  value = [],
  onChange,
  renderSelectedItem,
  ...props
}: {
  label?: string;
  options?: T[] | { value: T; label: string }[];
  value?: T[];
  onChange?: (value: T[]) => void;
  renderItem?: (option: T | { value: T; label: string }) => React.ReactNode;
  renderSelectedItem?: (value: T[]) => React.ReactNode;
  grouped?: boolean;
  [key: string]: unknown;
}) {
  const normalized = options.map((option) =>
    typeof option === "string" ? { value: option as T, label: option } : option
  );

  return (
    <select
      multiple
      className="h-full min-w-44 rounded-lg border bg-background px-3 py-2 text-sm"
      value={value}
      onChange={(event) =>
        onChange?.(
          Array.from(event.currentTarget.selectedOptions).map(
            (option) => option.value as T
          )
        )
      }
      aria-label={label}
      {...props}
    >
      {normalized.map((option) => (
        <option key={option.value} value={option.value}>
          {option.label}
        </option>
      ))}
    </select>
  );
}

